-- Migracion 006: categoriza productos del distribuidor que no tenian categoria asignada
-- (2169 productos totales; esta migracion cubre 1692, el resto (477) queda para
-- categorizar a mano desde /admin/productos, son casos ambiguos por nombre solo).
-- Nunca pisa una categoria ya asignada (todos los WHERE son sobre category_id is null
-- ademas del sku, por seguridad).
-- Correr una sola vez en el SQL Editor de Supabase.

-- 1) Categorias nuevas (el catalogo real incluye electronica, muebles y
-- electrodomesticos que no encajaban en las 12 categorias originales)
insert into categories (name, slug, sort_order) values
  ('Electrónica', 'electronica', 14),
  ('Muebles', 'muebles', 15),
  ('Electrodomésticos', 'electrodomesticos', 16),
  ('Climatización', 'climatizacion', 17),
  ('Deportes y Aire Libre', 'deportes-aire-libre', 18)
on conflict (slug) do update set name = excluded.name, sort_order = excluded.sort_order;

-- 2) Asignacion de categoria por SKU (agrupado por categoria destino)

